# Bare-minimum sketch of what a 402-aware agent tool wrapper needs
def call_tool_with_payment(endpoint, payload, wallet, budget_guard):
    response = http.post(endpoint, json=payload)

    if response.status_code == 402:
        challenge = parse_x402_challenge(response.headers)

        # Hard stop before spending anything
        budget_guard.assert_within_limit(challenge.amount)

        proof = wallet.sign_payment(challenge)
        response = http.post(
            endpoint,
            json=payload,
            headers={"X-Payment": proof.serialize()}
        )

    response.raise_for_status()
    return response.json()
